from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "No external services path provided; cannot check jira_state.json."}
    jira_path = Path(external_services_path) / "jira_state.json"
    if not jira_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "jira_state.json not found at expected path."}
    with open(jira_path, encoding="utf-8") as f:
        data = json.load(f)

    issues = data.get("issues", {})
    all_issues = list(issues.values()) if isinstance(issues, dict) else issues

    def get_summary(i):
        return (i.get("fields", {}).get("summary") or i.get("summary") or "").strip()

    def get_project_key(i):
        p = i.get("fields", {}).get("project") or i.get("project") or ""
        if isinstance(p, dict):
            return (p.get("key") or p.get("name") or "").upper().strip()
        return str(p).upper().strip()

    def extract_description_text(i):
        desc = i.get("fields", {}).get("description") or i.get("description") or {}
        if isinstance(desc, dict):
            try:
                return desc["content"][0]["content"][0]["text"]
            except (KeyError, IndexError, TypeError):
                return str(desc)
        return str(desc)

    target_summary = "LEAVE-Torres-04122026"
    matched = [i for i in all_issues if get_summary(i) == target_summary]

    if len(matched) == 0:
        all_summaries = [get_summary(i) for i in all_issues]
        return {"pass": False, "score": 0.0, "feedback": f"No issue found with summary '{target_summary}'. All summaries: {all_summaries}"}
    if len(matched) > 1:
        return {"pass": False, "score": 0.0, "feedback": f"Expected exactly 1 issue with summary '{target_summary}', found {len(matched)}."}

    issue = matched[0]
    proj = get_project_key(issue)
    if "LEAVE" not in proj:
        return {"pass": False, "score": 0.0, "feedback": f"Issue found but project is '{proj}', expected 'LEAVE'."}

    desc_text = extract_description_text(issue)
    required = [
        "Employee Name: Maria Torres",
        "Employee ID: E-1001",
        "Assignee: Patricia Huang",
    ]
    missing = [term for term in required if term.lower() not in desc_text.lower()]
    if missing:
        return {"pass": False, "score": 0.0, "feedback": f"Issue '{target_summary}' found in LEAVE project but description is missing: {missing}. Description: '{desc_text[:300]}'"}

    return {"pass": True, "score": 1.0, "feedback": f"Issue '{target_summary}' found in LEAVE project with all required description fields."}

