def verify(workspace_path, external_services_path=None):
    workspace_path = Path(workspace_path)
    feedback_parts = []
    all_pass = True

    # Helper: find column index by header name (case-insensitive, stripped)
    def find_col(headers, name):
        name_lower = name.strip().lower()
        for i, h in enumerate(headers):
            if h is not None and str(h).strip().lower() == name_lower:
                return i
        return None

    def cell_matches(val, target):
        if val is None:
            return False
        return str(val).strip().lower() == str(target).strip().lower()

    def is_empty(val):
        if val is None:
            return True
        s = str(val).strip()
        return s == '' or s.lower() in ('none', 'n/a', 'na', 'null', 'nat')

    # --- Check 1: employee_roster.xlsx ---
    roster_file = workspace_path / 'employee_roster.xlsx'
    if not roster_file.exists():
        all_pass = False
        feedback_parts.append(f"FAIL: '{roster_file.name}' not found in workspace.")
    else:
        wb = openpyxl.load_workbook(roster_file, data_only=True)
        ws = wb[wb.sheetnames[0]]  # Sheet1
        rows = list(ws.iter_rows(values_only=True))
        if len(rows) < 2:
            all_pass = False
            feedback_parts.append(f"FAIL: '{roster_file.name}' has no data rows.")
        else:
            headers = [str(h).strip().lower() if h is not None else '' for h in rows[0]]
            # find relevant columns
            emp_id_col = None
            name_col = None
            status_col = None
            for i, h in enumerate(headers):
                if 'employee' in h and 'id' in h:
                    emp_id_col = i
                elif h in ('name', 'employee_name', 'employee name', 'full_name', 'full name'):
                    name_col = i
                elif h == 'first_name' or h == 'first name':
                    name_col = i  # fallback
                if h == 'status':
                    status_col = i

            found_row = None
            for row in rows[1:]:
                match = False
                if emp_id_col is not None and row[emp_id_col] is not None:
                    if str(row[emp_id_col]).strip().upper().replace(' ', '') in ('E-1003', 'E1003'):
                        match = True
                if not match and name_col is not None and row[name_col] is not None:
                    if 'okafor' in str(row[name_col]).strip().lower() and 'james' in str(row[name_col]).strip().lower():
                        match = True
                if not match:
                    # brute force: check all cells for E-1003 or James Okafor
                    row_str = ' '.join([str(c).strip().lower() for c in row if c is not None])
                    if ('e-1003' in row_str or 'e1003' in row_str) or ('james' in row_str and 'okafor' in row_str):
                        match = True
                if match:
                    found_row = row
                    break

            if found_row is None:
                all_pass = False
                feedback_parts.append(f"FAIL: No row for James Okafor (E-1003) found in '{roster_file.name}'.")
            else:
                if status_col is not None:
                    status_val = found_row[status_col]
                    if status_val is not None and str(status_val).strip().lower() == 'active':
                        feedback_parts.append(f"PASS: '{roster_file.name}' - James Okafor status is 'Active' (found: '{status_val}').")
                    else:
                        all_pass = False
                        feedback_parts.append(f"FAIL: '{roster_file.name}' - James Okafor status expected 'Active', found '{status_val}'.")
                else:
                    # Try to find status in row by scanning headers more broadly
                    all_pass = False
                    feedback_parts.append(f"FAIL: '{roster_file.name}' - Could not find 'status' column. Headers: {headers}")
        wb.close()

    # --- Check 2 & 3: benefits_enrollment.xlsx ---
    benefits_file = workspace_path / 'benefits_enrollment.xlsx'
    if not benefits_file.exists():
        all_pass = False
        feedback_parts.append(f"FAIL: '{benefits_file.name}' not found in workspace.")
    else:
        wb = openpyxl.load_workbook(benefits_file, data_only=True)
        ws = wb[wb.sheetnames[0]]  # Sheet1
        rows = list(ws.iter_rows(values_only=True))
        if len(rows) < 2:
            all_pass = False
            feedback_parts.append(f"FAIL: '{benefits_file.name}' has no data rows.")
        else:
            headers = [str(h).strip().lower() if h is not None else '' for h in rows[0]]
            emp_id_col = None
            name_col = None
            status_col = None
            cobra_col = None
            for i, h in enumerate(headers):
                if 'employee' in h and 'id' in h:
                    emp_id_col = i
                if h in ('name', 'employee_name', 'employee name', 'full_name', 'full name'):
                    name_col = i
                if h == 'first_name' or h == 'first name':
                    if name_col is None:
                        name_col = i
                if h == 'status':
                    status_col = i
                if 'cobra' in h and 'notif' in h:
                    cobra_col = i

            found_row = None
            for row in rows[1:]:
                match = False
                if emp_id_col is not None and row[emp_id_col] is not None:
                    if str(row[emp_id_col]).strip().upper().replace(' ', '') in ('E-1003', 'E1003'):
                        match = True
                if not match and name_col is not None and row[name_col] is not None:
                    if 'okafor' in str(row[name_col]).strip().lower() and 'james' in str(row[name_col]).strip().lower():
                        match = True
                if not match:
                    row_str = ' '.join([str(c).strip().lower() for c in row if c is not None])
                    if ('e-1003' in row_str or 'e1003' in row_str) or ('james' in row_str and 'okafor' in row_str):
                        match = True
                if match:
                    found_row = row
                    break

            if found_row is None:
                all_pass = False
                feedback_parts.append(f"FAIL: No row for James Okafor (E-1003) found in '{benefits_file.name}'.")
            else:
                # Check status == Active
                if status_col is not None:
                    status_val = found_row[status_col]
                    if status_val is not None and str(status_val).strip().lower() == 'active':
                        feedback_parts.append(f"PASS: '{benefits_file.name}' - James Okafor status is 'Active' (found: '{status_val}').")
                    else:
                        all_pass = False
                        feedback_parts.append(f"FAIL: '{benefits_file.name}' - James Okafor status expected 'Active', found '{status_val}'.")
                else:
                    all_pass = False
                    feedback_parts.append(f"FAIL: '{benefits_file.name}' - Could not find 'status' column. Headers: {headers}")

                # Check cobra_notification_date is empty/None
                if cobra_col is not None:
                    cobra_val = found_row[cobra_col]
                    if is_empty(cobra_val):
                        feedback_parts.append(f"PASS: '{benefits_file.name}' - James Okafor cobra_notification_date is empty (found: '{cobra_val}').")
                    else:
                        all_pass = False
                        feedback_parts.append(f"FAIL: '{benefits_file.name}' - James Okafor cobra_notification_date expected empty/None, found '{cobra_val}'.")
                else:
                    # Maybe the column doesn't exist yet, which means it's effectively empty
                    feedback_parts.append(f"PASS (lenient): '{benefits_file.name}' - No 'cobra_notification_date' column found, treating as empty for James Okafor.")
        wb.close()

    score = 1.0 if all_pass else 0.0
    feedback = '\n'.join(feedback_parts)
    return {"pass": all_pass, "score": score, "feedback": feedback}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox."}

    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"mailbox.json not found at {mailbox_path}"}

    with open(mailbox_path, "r") as f:
        mailbox = json.load(f)

    emails = mailbox.get("emails", [])

    target_email = None
    for email in emails:
        eid = email.get("email_id", "")
        if str(eid).strip() == "3":
            target_email = email
            break

    if target_email is None:
        return {"pass": False, "score": 0.0, "feedback": "Email with id=3 was not found in the mailbox at all."}

    folder = target_email.get("folder", "").strip()
    if folder.upper() == "INBOX":
        return {"pass": True, "score": 1.0, "feedback": f"Email id=3 is in folder '{folder}' as expected."}
    else:
        return {"pass": False, "score": 0.0, "feedback": f"Email id=3 is in folder '{folder}', expected 'INBOX'."}

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "No external services path provided; cannot check jira_state.json."}
    jira_path = Path(external_services_path) / "jira_state.json"
    if not jira_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "jira_state.json not found at expected path."}
    with open(jira_path, encoding="utf-8") as f:
        data = json.load(f)

    top_comments = data.get("comments", {})
    if not isinstance(top_comments, dict):
        return {"pass": False, "score": 0.0, "feedback": f"Expected 'comments' to be a dict, got {type(top_comments).__name__}."}

    offboard1_comments = top_comments.get("OFFBOARD-1", [])
    if not offboard1_comments:
        return {"pass": False, "score": 0.0, "feedback": "No comments found under 'OFFBOARD-1' in the top-level comments dict."}

    def extract_text(comment):
        body = comment.get("body", {})
        if isinstance(body, dict):
            try:
                return body["content"][0]["content"][0]["text"]
            except (KeyError, IndexError, TypeError):
                return str(body)
        return str(body)

    for comment in offboard1_comments:
        text = extract_text(comment)
        if "[11.4]" in text and "access" in text.lower():
            return {"pass": True, "score": 1.0, "feedback": f"Found comment on OFFBOARD-1 containing both '[11.4]' and 'Access': '{text[:200]}'"}

    texts = [extract_text(c)[:100] for c in offboard1_comments]
    return {"pass": False, "score": 0.0, "feedback": f"Found {len(offboard1_comments)} comment(s) on OFFBOARD-1 but none contain both '[11.4]' and 'Access'. Comments: {texts}"}
